 1	import * as React from 'react';
 2	import { DeploymentType } from '@odf/core/types';
 3	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 4	import { TFunction } from 'react-i18next';
 5	import { Select, SelectOption, SelectProps } from '@patternfly/react-core';
 6	import {
 7	  FormGroup,
 8	  MenuToggle,
 9	  MenuToggleElement,
10	  SelectList,
11	} from '@patternfly/react-core';
12	import { WizardDispatch, WizardState } from '../../reducer';
13	import './backing-storage-step.scss';
14	
15	const selectOptions = (t: TFunction) => {
16	  const options = [DeploymentType.FULL, DeploymentType.MCG];
17	
18	  const optionsDescription = {
19	    [DeploymentType.MCG]: t(
20	      'Deploys MultiCloud Object Gateway without block and file services.'
21	    ),
22	    [DeploymentType.FULL]: t(
23	      'Deploys Data Foundation with block, shared fileSystem and object services.'
24	    ),
25	  };
26	
27	  return options.map((option) => (
28	    <SelectOption
29	      key={option}
30	      value={option}
31	      description={optionsDescription[option]}
32	    >
33	      {option}
34	    </SelectOption>
35	  ));
36	};
37	
38	export const SelectDeployment: React.FC<SelectDeploymentProps> = ({
39	  deployment,
40	  dispatch,
41	}) => {
42	  const { t } = useCustomTranslation();
43	  const [isSelectOpen, setIsSelectOpen] = React.useState(false);
44	
45	  const handleSelection: SelectProps['onSelect'] = (_, value) => {
46	    dispatch({
47	      type: 'backingStorage/setDeployment',
48	      // 'value' on SelectProps['onSelect'] is string hence does not match with payload of type "DeploymentType"
49	      payload: value as DeploymentType,
50	    });
51	    setIsSelectOpen(false);
52	  };
53	
54	  const onToggleClick = () => {
55	    setIsSelectOpen(!isSelectOpen);
56	  };
57	
58	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
59	    <MenuToggle
60	      ref={toggleRef}
61	      onClick={onToggleClick}
62	      isExpanded={isSelectOpen}
63	      className="odf-backing-storage__selection--width"
64	      isFullWidth
65	    >
66	      {deployment}
67	    </MenuToggle>
68	  );
69	
70	  return (
71	    <FormGroup label={t('Deployment type')} fieldId="deployment-type">
72	      <Select
73	        onSelect={handleSelection}
74	        selected={deployment}
75	        isOpen={isSelectOpen}
76	        onOpenChange={(isOpen) => setIsSelectOpen(isOpen)}
77	        toggle={toggle}
78	        shouldFocusToggleOnSelect
79	        popperProps={{ width: 'trigger' }}
80	      >
81	        <SelectList>{selectOptions(t)}</SelectList>
82	      </Select>
83	    </FormGroup>
84	  );
85	};
86	
87	type SelectDeploymentProps = {
88	  dispatch: WizardDispatch;
89	  deployment: WizardState['backingStorage']['deployment'];
90	};

